{
  "type": "Close-up prop photography",
  "subject": "A clearly fictional prop identification card held by a hand, designed for film set dressing, UI mockups, or visual design study only",
  "safety_constraints": [
    "The card must be visibly invalid and impossible to mistake for a real government ID",
    "Place a large diagonal SPECIMEN / NOT VALID ID watermark across the front",
    "Use only fictional jurisdiction names, fictional department labels, and placeholder personal data",
    "Do not use real agency names, official seals, government marks, real addresses, real license numbers, or real document formats",
    "Any barcode-like area must be decorative, broken, non-scannable, and labeled SAMPLE ONLY",
    "Avoid security features that appear operational; make holograms decorative and obviously fictional"
  ],
  "card_content": {
    "header": {
      "fictional_place_name": "SAMPLE STATE",
      "document_title": "PROP IDENTIFICATION CARD",
      "emblem": "A decorative gold foil circle with abstract stars, visibly labeled SPECIMEN"
    },
    "portrait": {
      "appearance": "Fictional adult character with neutral expression, studio-lit portrait, not based on a real person",
      "clothing": "Simple dark collared shirt"
    },
    "placeholder_text_data": {
      "card_number": "SAMPLE-0000-0000",
      "full_name": "JONATHAN SAMPLE",
      "address": "000 SAMPLE AVENUE, FICTIONAL CITY",
      "date_fields": "clearly marked placeholder dates",
      "status": "NOT A VALID DOCUMENT"
    },
    "decorative_barcode_area": "Broken non-scannable barcode pattern labeled SAMPLE ONLY",
    "surface_texture": "Matte polycarbonate prop card with slight edge wear, decorative non-official holographic overlay"
  },
  "foreground_hand": {
    "position": "Holding the card between thumb and middle finger by the right edge",
    "skin_tone": "Natural skin tone",
    "fingernail": "Short, clean, no polish"
  },
  "background": "Dark denim fabric as the lap surface",
  "lighting": "Natural daylight from a window on the left, soft gradient across the card, decorative hologram catching light with a subtle rainbow sheen",
  "framing": "Horizontal close-up, card angled about 15 degrees, focus on the watermark, portrait area, and prop-card texture",
  "negative_prompt": "real government ID, real license, scannable barcode, official seal, usable document, authentic DMV design, identity document forgery"
}

